Why would someone want to learn Unix Programming using OCAML? Not a smart choice. Also this does not look easier to read than a shell script either.<p>let rec copy_rec source dest =
  let infos = lstat source in
  match infos.st_kind with
  | S_REG -&gt;
      file_copy source dest;
      set_infos dest infos
  | S_LNK -&gt;
      let link = readlink source in
      symlink link dest
  | S_DIR -&gt;
      mkdir dest 0o200;
      Misc.iter_dir
        (fun file -&gt;
          if file &lt;&gt; Filename.current_dir_name
              &amp;&amp; file &lt;&gt; Filename.parent_dir_name
          then
            copy_rec
              (Filename.concat source file)
              (Filename.concat dest file))
        source;
      set_infos dest infos
  | _ -&gt;
      prerr_endline (&quot;Can&#x27;t cope with special file &quot; ^ source)

